  return nodes
    .map(node => {
      const prefix = "  ".repeat(indent) + "- ";
      const children = node.children.length > 0
        ? "\n" + formatCategoryTree(node.children, indent + 1)
        : "";
      return prefix + node.name + children;
    })
    .join("\n");
}
