```ts
sources: SourcesSchema.refine(
  (s) => s.github || s.arxiv || s.blogs || s.web_pages || s.registries,
  "At least one source must be configured"
),
```

### 3. Registry collectors (new `src/sources/registry.ts`)

Create new file with three collectors:

```ts
import * as core from "@actions/core";
import type { RadarConfig } from "../config";
import type { Candidate } from "./types";

interface RegistryEntry {
  type: "npm" | "pypi" | "crates";
  keywords: string[];
  min_downloads: number;
  max_results: number;
}

async function collectNpm(
  entry: RegistryEntry,
  fetchFn: typeof fetch
): Promise<Candidate[]> {
  const candidates: Candidate[] = [];
  const query = entry.keywords.join("+");
  const url = `https://registry.npmjs.org/-/v1/search?text=${encodeURIComponent(query)}&size=${entry.max_results}`;

  const response = await fetchFn(url);
  if (!response.ok) {
    core.warning(`npm search failed: HTTP ${response.status}`);
    return [];
  }

  const data = await response.json() as any;
  for (const result of data.objects ?? []) {
    const pkg = result.package;
    const downloads = result.score?.detail?.popularity ?? 0;
    // npm doesn't return download counts directly in search, use popularity score
    // For min_downloads filtering, skip if score is below threshold mapped

    candidates.push({
      url: `https://www.npmjs.com/package/${pkg.name}`,
      title: pkg.name,
      description: (pkg.description ?? "").slice(0, 1000),
      source: "registry",
      metadata: {
        language: "JavaScript",
        publishedAt: pkg.date,
      },
    });
  }

  return candidates;
}

async function collectPyPI(
  entry: RegistryEntry,
  fetchFn: typeof fetch
): Promise<Candidate[]> {
  const candidates: Candidate[] = [];

  // PyPI JSON search API (unofficial but stable)
  // Use the simple search: https://pypi.org/simple/ doesn't support keyword search
  // Use warehouse JSON API for search-like functionality
  // Best approach: use PyPI's XML-RPC or RSS feed for recent packages
  // Simplest: search via the JSON API
  for (const keyword of entry.keywords) {
    const url = `https://pypi.org/pypi/${encodeURIComponent(keyword)}/json`;
    try {
      const response = await fetchFn(url);
      if (!response.ok) continue;

      const data = await response.json() as any;
      const info = data.info;
      if (!info) continue;

      candidates.push({
        url: `https://pypi.org/project/${info.name}/`,
        title: info.name,
        description: (info.summary ?? "").slice(0, 1000),
        source: "registry",
        metadata: {
          language: "Python",
          publishedAt: data.urls?.[0]?.upload_time_iso_8601,
        },
      });
    } catch {
      core.warning(`PyPI lookup failed for "${keyword}"`);
    }
  }

  return candidates;
}

async function collectCrates(
  entry: RegistryEntry,
  fetchFn: typeof fetch
): Promise<Candidate[]> {
  const candidates: Candidate[] = [];
  const query = entry.keywords.join("+");
  const url = `https://crates.io/api/v1/crates?q=${encodeURIComponent(query)}&per_page=${entry.max_results}&sort=downloads`;

  const response = await fetchFn(url, {
    headers: { "User-Agent": "awesome-list-radar (https://github.com/moven0831/awesome-list-radar)" },
  });
  if (!response.ok) {
    core.warning(`crates.io search failed: HTTP ${response.status}`);
    return [];
  }

  const data = await response.json() as any;
  for (const crate of data.crates ?? []) {
    if (entry.min_downloads > 0 && (crate.downloads ?? 0) < entry.min_downloads) {
      continue;
    }

    candidates.push({
      url: `https://crates.io/crates/${crate.name}`,
      title: crate.name,
      description: (crate.description ?? "").slice(0, 1000),
      source: "registry",
      metadata: {
        language: "Rust",
        publishedAt: crate.updated_at,
      },
    });
  }

  return candidates;
}

export async function collectRegistries(
  config: RadarConfig,
  fetchFn: typeof fetch = fetch
): Promise<Candidate[]> {
  if (!config.sources.registries) return [];

  const candidates: Candidate[] = [];

  for (const entry of config.sources.registries) {
    try {
      let results: Candidate[];
      switch (entry.type) {
        case "npm":
          results = await collectNpm(entry, fetchFn);
          break;
        case "pypi":
          results = await collectPyPI(entry, fetchFn);
          break;
        case "crates":
          results = await collectCrates(entry, fetchFn);
          break;
      }
      core.info(`Registry ${entry.type}: found ${results.length} candidates`);
      candidates.push(...results);
    } catch (error) {
      core.warning(
        `Registry ${entry.type} collection failed: ${error instanceof Error ? error.message : String(error)}`
      );
    }
  }

  return candidates;
}
```

### 4. Wire up in `src/index.ts`

Add import and call:
