## Branch: `feat/13-retry-utility`

Create branch `feat/13-retry-utility` from main, implement, test, commit, push, and create PR.

## Project Context

- TypeScript project using Bun, Vitest for tests, Zod for schemas
- Source files in `src/`, tests in `tests/` (mirroring src structure)
- Tests use `vi.mock("@actions/core", ...)` pattern
- Build: `bun run build` (ncc), Lint: `bun run lint` (tsc --noEmit), Test: `bun test`

## What to Implement

### 1. Retry utility (new `src/utils/retry.ts`)

```ts
import * as core from "@actions/core";

export interface RetryOptions {
  maxRetries?: number;     // default 3
  baseDelay?: number;      // default 1000 (ms)
  maxDelay?: number;       // default 30000 (ms)
  retryableStatuses?: number[]; // default [408, 429, 500, 502, 503, 504]
}

interface RetryableError extends Error {
  status?: number;
  response?: {
    status: number;
    headers: {
      get(name: string): string | null;
    };
  };
}

function getRetryDelay(attempt: number, options: Required<RetryOptions>): number {
  // Exponential backoff with jitter
  const exponential = options.baseDelay * Math.pow(2, attempt);
  const jitter = Math.random() * options.baseDelay;
  return Math.min(exponential + jitter, options.maxDelay);
}

function getRateLimitDelay(error: RetryableError): number | null {
  const headers = error.response?.headers;
  if (!headers) return null;

  // Check Retry-After header
  const retryAfter = headers.get("retry-after");
  if (retryAfter) {
    const seconds = parseInt(retryAfter, 10);
    if (!isNaN(seconds)) return seconds * 1000;
    // Could be a date
    const date = new Date(retryAfter).getTime();
    if (!isNaN(date)) return Math.max(0, date - Date.now());
  }

  // Check X-RateLimit-Reset
  const rateLimitReset = headers.get("x-ratelimit-reset");
  if (rateLimitReset) {
    const resetTime = parseInt(rateLimitReset, 10) * 1000; // Unix timestamp in seconds
    return Math.max(0, resetTime - Date.now());
  }

  return null;
}

function isRetryable(error: unknown, retryableStatuses: number[]): boolean {
  if (error instanceof Error) {
    const retryable = error as RetryableError;
    const status = retryable.status ?? retryable.response?.status;
    if (status && retryableStatuses.includes(status)) return true;

    // Network errors
    if (retryable.message.includes("ECONNRESET") ||
        retryable.message.includes("ETIMEDOUT") ||
        retryable.message.includes("ENOTFOUND") ||
        retryable.message.includes("fetch failed")) {
      return true;
    }
  }
  return false;
}

export async function withRetry<T>(
  fn: () => Promise<T>,
  options?: RetryOptions
): Promise<T> {
  const opts: Required<RetryOptions> = {
    maxRetries: options?.maxRetries ?? 3,
    baseDelay: options?.baseDelay ?? 1000,
    maxDelay: options?.maxDelay ?? 30000,
    retryableStatuses: options?.retryableStatuses ?? [408, 429, 500, 502, 503, 504],
  };

  let lastError: unknown;

  for (let attempt = 0; attempt <= opts.maxRetries; attempt++) {
    try {
      return await fn();
    } catch (error) {
      lastError = error;

      if (attempt === opts.maxRetries || !isRetryable(error, opts.retryableStatuses)) {
        throw error;
      }

      // Check for rate limit delay
      const rateLimitDelay = getRateLimitDelay(error as RetryableError);
      const delay = rateLimitDelay ?? getRetryDelay(attempt, opts);

      core.info(`Retry ${attempt + 1}/${opts.maxRetries} after ${Math.round(delay)}ms: ${error instanceof Error ? error.message : String(error)}`);

      await new Promise(resolve => setTimeout(resolve, delay));
    }
  }

  throw lastError;
}
```

