```ts
import { readFileSync, writeFileSync } from "node:fs";
import * as core from "@actions/core";
import type { Candidate } from "./sources/types";

export interface SeenEntry {
  status: "accepted" | "rejected" | "filtered";
  seen_at: string;
}

export interface SourceWatermark {
  last_run: string;
  last_result_id?: string;
}

export interface RadarState {
  seen_urls: Record<string, SeenEntry>;
  watermarks: Record<string, SourceWatermark>;
}

const EMPTY_STATE: RadarState = {
  seen_urls: {},
  watermarks: {},
};

export function loadState(filePath: string): RadarState {
  try {
    const content = readFileSync(filePath, "utf-8");
    const parsed = JSON.parse(content);
    // Validate basic structure
    if (typeof parsed === "object" && parsed !== null && typeof parsed.seen_urls === "object") {
      return {
        seen_urls: parsed.seen_urls ?? {},
        watermarks: parsed.watermarks ?? {},
      };
    }
    core.warning(`Invalid state file structure, starting fresh`);
    return { ...EMPTY_STATE };
  } catch {
    core.info(`No existing state file at "${filePath}", starting fresh`);
    return { ...EMPTY_STATE };
  }
}

export function saveState(filePath: string, state: RadarState): void {
  writeFileSync(filePath, JSON.stringify(state, null, 2), "utf-8");
  core.info(`State saved to "${filePath}" (${Object.keys(state.seen_urls).length} URLs tracked)`);
}

export function filterSeenCandidates(
  candidates: Candidate[],
  state: RadarState
): Candidate[] {
  const before = candidates.length;
  const filtered = candidates.filter(c => {
    const normalized = c.url.toLowerCase();
    return !state.seen_urls[normalized];
  });

  if (before !== filtered.length) {
    core.info(`State filter: ${before} → ${filtered.length} candidates (${before - filtered.length} already seen)`);
  }

  return filtered;
}

export function recordCandidates(
  state: RadarState,
  candidates: Candidate[],
  status: "accepted" | "rejected" | "filtered"
): void {
  const now = new Date().toISOString();
  for (const c of candidates) {
    state.seen_urls[c.url.toLowerCase()] = { status, seen_at: now };
  }
}

export function updateWatermark(
  state: RadarState,
  sourceKey: string,
  lastResultId?: string
): void {
  state.watermarks[sourceKey] = {
    last_run: new Date().toISOString(),
    last_result_id: lastResultId,
  };
}
```

### 3. Integration in `src/index.ts`

Modify the pipeline to use state:

```ts
import { loadState, saveState, filterSeenCandidates, recordCandidates } from "./state";

async function run(): Promise<void> {
  try {
    const configPath = core.getInput("config_path");
    const dryRun = core.getInput("dry_run") === "true";

    core.info(`Loading config from ${configPath}`);
    const config = loadConfig(configPath);

    // Load state
    const state = loadState(config.state_file);

    const result = await runPipeline(
      config,
      {
        collect,
        filter: async (candidates, cfg) => {
          // First filter out already-seen candidates
          const unseen = filterSeenCandidates(candidates, state);
          // Record filtered-out candidates (the ones not already seen but filtered by keywords/dedup)
          const keywordFiltered = filterCandidates(unseen, cfg);
          const metadataResult = dedup(keywordFiltered, cfg);

          // Record candidates that were filtered out
          const filteredOut = unseen.filter(c => !metadataResult.includes(c));
          recordCandidates(state, filteredOut, "filtered");

          return metadataResult;
        },
        classify: async (candidates, cfg) => {
          const classified = await classifyCandidates(candidates, cfg);

          // Record accepted (classified) and rejected (below threshold) candidates
          const classifiedUrls = new Set(classified.map(c => c.url));
          const rejected = candidates.filter(c => !classifiedUrls.has(c.url));
          recordCandidates(state, classified, "accepted");
          recordCandidates(state, rejected, "rejected");

          return classified;
        },
        output: createIssues,
      },
      dryRun
    );

    // Save state
    saveState(config.state_file, state);

    core.setOutput("candidates_found", result.candidatesFound);
    core.setOutput("candidates_filtered", result.candidatesFiltered);
    core.setOutput("issues_created", result.issuesCreated);
  } catch (error) {
    if (error instanceof Error) {
      core.setFailed(error.message);
    } else {
      core.setFailed("An unexpected error occurred");
    }
  }
}
```

