 1→import { Octokit } from "@octokit/rest";
 2→import * as core from "@actions/core";
 3→import type { RadarConfig } from "../config";
 4→import type { Candidate } from "./types";
 5→
 6→const MAX_DESCRIPTION_LENGTH = 1000;
 7→
 8→function createdAfterDate(spec: string): string {
 9→  const days = parseInt(spec.replace("d", ""), 10);
10→  if (Number.isNaN(days)) {
11→    throw new Error(`Invalid date spec: ${spec}`);
12→  }
13→  const date = new Date();
14→  date.setDate(date.getDate() - days);
15→  return date.toISOString().split("T")[0];
16→}
17→
18→function buildSearchQuery(
19→  topics: string[],
20→  config: RadarConfig
21→): string {
22→  const gh = config.sources.github!;
23→  const parts: string[] = [];
24→
25→  // Use OR for topics: match repos with any of the listed topics
26→  const topicClauses = topics.map((t) => `topic:${t}`);
27→  parts.push(topicClauses.join(" "));
28→
29→  if (gh.languages) {
30→    // Use OR for languages: match repos in any of the listed languages
31→    const langClauses = gh.languages.map((l) => `language:${l}`);
32→    parts.push(langClauses.join(" "));
33→  }
34→
35→  if (gh.min_stars > 0) {
36→    parts.push(`stars:>=${gh.min_stars}`);
37→  }
38→
39→  const after = createdAfterDate(gh.created_after);
40→  parts.push(`created:>=${after}`);
41→
42→  return parts.join(" ");
43→}
44→
45→export async function collectGitHub(
46→  config: RadarConfig,
47→  octokit?: Octokit
48→): Promise<Candidate[]> {
49→  if (!config.sources.github) return [];
50→
51→  const client =
52→    octokit ?? new Octokit({ auth: core.getInput("github_token") });
53→  const query = buildSearchQuery(config.sources.github.topics, config);
54→
55→  core.info(`GitHub search query: ${query}`);
56→
57→  const candidates: Candidate[] = [];
58→
59→  try {
60→    // Note: fetches a single page (100 results) sorted by stars.
61→    // GitHub Search API supports up to 1000 results via pagination,
62→    // but for a radar scan the top 100 by stars is sufficient.
63→    const response = await client.search.repos({
64→      q: query,
65→      sort: "stars",
66→      order: "desc",
67→      per_page: 100,
68→    });
69→
70→    for (const repo of response.data.items) {
71→      candidates.push({
72→        url: repo.html_url,
73→        title: repo.full_name,
74→        description: (repo.description ?? "").slice(0, MAX_DESCRIPTION_LENGTH),
75→        source: "github",
76→        metadata: {
77→          stars: repo.stargazers_count,
78→          language: repo.language ?? undefined,
79→          topics: repo.topics ?? [],
80→        },
81→      });
82→    }
83→  } catch (error) {
84→    core.warning(
85→      `GitHub search failed: ${error instanceof Error ? error.message : String(error)}`
86→    );
87→  }
88→
89→  return candidates;
90→}
91→
92→export { buildSearchQuery, createdAfterDate };
93→

