 53→export async function collectGitHub(
 54→  config: RadarConfig,
 55→  octokit?: Octokit
 56→): Promise<Candidate[]> {
 57→  if (!config.sources.github) return [];
 58→
 59→  const client =
 60→    octokit ?? new Octokit({ auth: core.getInput("github_token") });
 61→  const query = buildSearchQuery(config.sources.github.topics, config);
 62→
 63→  core.info(`GitHub search query: ${query}`);
 64→
 65→  const candidates: Candidate[] = [];
 66→
 67→  try {
 68→    const gh = config.sources.github;
 69→    const maxResults = gh.max_results;
 70→    let page = 1;
 71→    let fetched = 0;
 72→
 73→    while (fetched < maxResults) {
 74→      const remaining = maxResults - fetched;
 75→      const perPage = Math.min(remaining, 100);
 76→      const response = await client.search.repos({
 77→        q: query,
 78→        sort: gh.sort === "best-match" ? undefined : gh.sort,
 79→        order: "desc",
 80→        per_page: perPage,
 81→        page,
 82→      });
 83→
 84→      for (const repo of response.data.items) {
 85→        if (fetched >= maxResults) break;
 86→        candidates.push({
 87→          url: repo.html_url,
 88→          title: repo.full_name,
 89→          description: (repo.description ?? "").slice(0, MAX_DESCRIPTION_LENGTH),
 90→          source: "github",
 91→          metadata: {
 92→            stars: repo.stargazers_count,
 93→            language: repo.language ?? undefined,
 94→            topics: repo.topics ?? [],
 95→          },
 96→        });
 97→        fetched++;
 98→      }
 99→
100→      if (response.data.items.length < perPage || fetched >= response.data.total_count) break;
101→      page++;
102→    }
103→  } catch (error) {
104→    core.warning(
105→      `GitHub search failed: ${error instanceof Error ? error.message : String(error)}`
106→    );
107→  }
108→
109→  return candidates;
110→}
