 9→function createdAfterDate(spec: string): string {
10→  const days = parseInt(spec.replace("d", ""), 10);
11→  if (Number.isNaN(days)) {
12→    throw new Error(`Invalid date spec: ${spec}`);
13→  }
14→  const date = new Date();
15→  date.setDate(date.getDate() - days);
16→  return date.toISOString().split("T")[0];
17→}
